/* 地雷病-小羊莓 */
/* 禁止二传贩卖 */
/* 感谢名单：
代码：部分来自lc美化教程贴的所有老师们（感谢老师们）
图标等装饰等均来自小红书：@抹茶绿豆 @亚由 @桃吱 @乌云 @记录（感谢老师们分享的素材）*/


/*1. 字体与全局背景 */
/* --- 自定义字体 --- */
@import url("https://fontsapi.zeoseven.com/701/main/result.css"); /* 🍓替换字体链接 */
body, button, input, textarea, select {
  font-family: "NaikaiFont", sans-serif !important;
  font-weight: normal !important;
}
/* --- 界面全局背景 --- */
.drawer-content {
  background: 
    linear-gradient(rgba(250, 248, 255, 0), rgba(250, 248, 255, 0)),
    url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center / cover no-repeat fixed !important; /* 🍓全局背景*/
}

/* 1. 🍓全局控制中心中文版 @lazyalie宝宝的建议*/
:root {
    /* --- 1. 顶部导航栏 (Top Bar) --- */
    --导航-垂直位移: 0px;        
    --导航-水平位移: 0px;        
    --导航-宽度: 100%;      
    --导航-高度: 50px;     
    --导航-背景图: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
    --导航-图标大小: 30px;    
    --导航-图标上边距: -20px; 

    /* --- 2. 聊天气泡主体 (Message Bubble) --- */
    --气泡-最大宽度: 500px; 
    --名字容器高度: 0px;        
    --正文-上方间距: 5px;       
    --正文-下方间距: 40px;      
    --正文-左边距: 25px; 
    --正文-右边距: 25px;
    --气泡-上方外部留空: 230px; 
    --气泡-下方外部留空: 60px;  
    --气泡-中段背景图: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII="); 

    /* --- 3. 信息栏位置 (楼层/字符/计时) --- */
    --楼层-上下位置: -130px;
    --楼层-左右位置: 70px;
    --字符-上下位置: -152px;
    --字符-左右位置: 40px;
    --计时-上下位置: -28px;
    --计时-左右位置: 98px;

    /* --- 4. 气泡装饰贴纸 (Stickers) --- */
    --上层贴纸-图片: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
    --上层贴纸-宽度: 370px;    
    --上层贴纸-高度: 305px;   
    --上层贴纸-水平偏移: 6px;  
    --上层贴纸-垂直偏移: 54px;  
    --下层贴纸-图片: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
    --下层贴纸-宽度: 358px; 
    --下层贴纸-高度: 80px; 
    --下层贴纸-水平偏移: 0px;
    --下层贴纸-垂直偏移: -18px;

    /* --- 5. 头像美化 (Avatar) --- */
    --头像-大小: 218px; 
    --头像-上下位移: -200px; 
    --头像-左右位移: 120px;
    --头像-旋转角度: +15deg; 

    /* --- 6. 名字与时间戳 --- */
    --名字-上下位移: -65px;
    --名字-左右位移: 52px;
    --名字-字体大小: 1em; 
    --名字-颜色: #c8b1c8; 

    --时间-字体大小: 9px; 
    --时间-颜色: #c8b1c8; 
    --时间-上下位移: -42px;     
    --时间-左右位移: 28px;    

    /* --- 7. 编辑/保存确认条 (Edit Bar) --- */
    --编辑条-上方偏移: -40px;    
    --编辑条-右侧偏移: 20px;   
    --编辑条-背景色: rgba(30, 15, 22, 0.98);
    --编辑条-模糊度: blur(8px);
    --编辑条-边框色: #ffb7d5;
    --编辑条-按钮底色: rgba(243, 242, 242, 1);
    --图标组-上下: -10px;
    --图标组-左右: 30px;

    /* --- 8. 颜色控制 --- */
    --地雷系粉色: #ffb7d5;  
    --地雷系边框: #3d1a2a; 
}

/* 代码部分 */
/* 导航栏设置 - @尾巴老师和bule老师适配drawer和fa的同级关系的简化顶框 */
#top-settings-holder {
    position: relative !important;
    top: var(--导航-垂直位移) !important;
    left: var(--导航-水平位移) !important;
    width: var(--导航-宽度) !important;
    height: var(--导航-高度) !important;
    background-image: var(--导航-背景图) !important; 
    background-size: 100% 100% !important;
    background-position: center !important;
    background-color: transparent !important; 
    display: flex !important;
    justify-content: center !important;
    align-items: center !important;
    padding: 5px 0 !important;
}

#top-settings-holder .drawer-icon::before {
    content: '' !important;
    visibility: hidden; 
}
#top-settings-holder .drawer { flex: 1; }
#top-settings-holder .drawer-icon {
    display: block; 
    margin: 0 auto;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    transition: all 0.3s ease-in-out;
    width: var(--导航-图标大小); 
    height: var(--导航-图标大小); 
    opacity: 1 !important;
    margin-top: var(--导航-图标上边距);
}

.drawer-icon.fa-fw:hover { transform: scale(1.2); }

/* 🍓 10个图标替换逻辑 (保持独立不合并) */
.drawer-icon.fa-sliders { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-plug { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-font { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-book-atlas { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-user-cog { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-panorama { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-cubes { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-bars-progress { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-face-smile { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }
.drawer-icon.fa-address-card { background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); }

#top-settings-holder .drawer .drawer-icon.openIcon {
    background-image: url(data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=) !important;
    transform: scale(1.1); 
}

/* 聊天气泡主界面 - @nini老师（二改版感谢老师） */
.mes:not(#chat-end) {
    position: relative !important;
    width: 100% !important;
    max-width: var(--气泡-最大宽度) !important;
    z-index: 2 !important;
    border: none !important;
    box-shadow: none !important;
    margin-left: auto !important;
    margin-right: auto !important;
    margin-top: var(--气泡-上方外部留空) !important;
    margin-bottom: var(--气泡-下方外部留空) !important;
    padding: var(--正文-上方间距) var(--正文-右边距) var(--正文-下方间距) var(--正文-左边距) !important;
    background-image: var(--气泡-中段背景图) !important;
    background-repeat: repeat-y !important;
    background-position: top center !important;
    background-size: 100% auto !important;
    background-color: transparent !important;
}

/* 消除名字容器占据的空隙 */
.mes_block .ch_name {
    min-height: var(--名字容器高度) !important;
    height: var(--名字容器高度) !important;
    margin: 0 !important;
    padding: 0 !important;
    overflow: visible !important; 
}

/* 正文与段落间距 */
.mes_text, .mes_reasoning {
    padding: 0 !important;
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    width: 100%;
    max-width: 100%;
    overflow-wrap: anywhere;
    box-sizing: border-box;
}
.mes_text p + p, .mes_reasoning p + p { margin-top: 10px !important; }

/* @lambkinling老师感谢 */
.mes_text { text-align: justify; }

/* 名字和时间戳移位修复 @ _nak.a.ri老师 */
.mes_block { transform: none !important; padding: 0 !important; }

/* 三元素修复移位 @ camellia1007老师 */
.mesAvatarWrapper { transform: none !important; }

/* 气泡贴纸 (上层与下层) */
.mes:not(#chat-end)::before {
    content: '';
    position: absolute;
    width: var(--上层贴纸-宽度);
    height: var(--上层贴纸-高度);
    top: 0; left: 50%;
    transform: translateY(-100%) translateX(-50%) translateX(var(--上层贴纸-水平偏移)) translateY(var(--上层贴纸-垂直偏移));
    pointer-events: none;
    z-index: 2;
    background-image: var(--上层贴纸-图片);
    background-size: contain; background-repeat: no-repeat; background-position: center;
}
.mes:not(#chat-end)::after {
    content: '';
    position: absolute;
    width: var(--下层贴纸-宽度);
    height: var(--下层贴纸-高度);
    top: 100%; left: 50%;
    transform: translateX(-50%) translateX(var(--下层贴纸-水平偏移)) translateY(var(--下层贴纸-垂直偏移));
    pointer-events: none;
    z-index: -1;
    background-image: var(--下层贴纸-图片);
    background-size: contain; background-repeat: no-repeat; background-position: center;
}

/* 头像美化 */
.mes .avatar {
    position: absolute !important;
    width: var(--头像-大小) !important;
    height: var(--头像-大小) !important;
    top: var(--头像-上下位移) !important;
    left: var(--头像-左右位移) !important;
    z-index: 1 !important;
    transform: rotate(var(--头像-旋转角度)) !important;
    transform-origin: center center !important;
    -webkit-mask-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'><path d='M12 4.435C10 0 0 0 0 8c0 4 3 9.5 12 15 9-5.5 12-11 12-15 0-8-10-8-12-3.565z'/></svg>") !important;
    mask-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'><path d='M12 4.435C10 0 0 0 0 8c0 4 3 9.5 12 15 9-5.5 12-11 12-15 0-8-10-8-12-3.565z'/></svg>") !important;
    -webkit-mask-repeat: no-repeat !important; mask-repeat: no-repeat !important;
    -webkit-mask-position: center !important; mask-position: center !important;
    -webkit-mask-size: 95% !important; mask-size: 95% !important;
    background: transparent !important; box-shadow: none !important;
}
.mes .avatar img { width: 100% !important; height: 100% !important; object-fit: cover !important; transform: scale(1) !important; }

/* 名字 */
.mes .name_text {
    position: absolute;
    top: var(--名字-上下位移);
    left: var(--名字-左右位移);     
    font-size: var(--名字-字体大小) !important;
    color: var(--名字-颜色) !important;
    transform: none;
    z-index: 35 !important;
}

/* 时间戳 */
.timestamp {
    position: absolute !important; 
    top: var(--时间-上下位移) !important;
    left: var(--时间-左右位移) !important;
    font-size: var(--时间-字体大小) !important;
    color: var(--时间-颜色) !important;
    font-weight: 400 !important;
    white-space: nowrap; opacity: 0.9 !important; z-index: 3 !important;
    text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.8) !important;
}


/* 修改/铅笔图标 @lazyalie宝宝一起修*/
.mes_buttons .fa-pencil::before {
    content: "";
    display: inline-block;
    width: 20px; height: 20px;
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/contain no-repeat;
    transform: translate(0px, 0px);
    opacity: 1 !important;
    filter: none !important;
}
/* 更多/三个点图标 */
.mes_buttons .fa-ellipsis::before {
    content: "";
    display: inline-block;
    width: 20px; height: 20px;
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/contain no-repeat;
    transform: translate(0px, 0px);
    opacity: 1 !important;
    filter: none !important;
}

i.fa-solid.fa-camera,
mes_buttons .fa-star,
.mes_buttons .fa-pencil, 
.mes_buttons .fa-ellipsis{opacity: 1 !important; 
    filter: none !important;
}
/*图标组 */
.mes_buttons {
    position: absolute !important;
    top: var(--图标组-上下) !important;
    right: var(--图标组-左右) !important; 
    left: auto !important;    
    display: flex;
    z-index: 2 !important;
}

/* 修复：发送消息/生成中隐藏编辑按钮 */
.mes.streaming .mes_buttons,
.mes.typing .mes_buttons {
    display: none !important;
}

#send_but:disabled ~ .mes .mes_buttons {
    display: none !important;
}

/* 编辑确认按钮条 */
.mes_edit_buttons {
    display: none; 
    position: absolute !important;
    flex-direction: row;
    align-items: center;
    padding: 4px 10px !important;   
    gap: 8px !important;     
    background: var(--编辑条-背景色) !important;
    backdrop-filter: var(--编辑条-模糊度);
    border-radius: 20px !important;    
    border: 1.5px double var(--编辑条-边框色) !important;
    box-shadow: 0 0 15px rgba(0, 0, 0, 0.8), 2px 4px 0px #000 !important;
    top: var(--编辑条-上方偏移) !important;
    right: var(--编辑条-右侧偏移) !important;
    z-index: 100 !important;
    transition: all 0.3s ease;
}

.mes_edit_buttons .menu_button {
    background-color: var(--编辑条-按钮底色) !important; 
    border: 1px solid rgba(255, 183, 213, 0.3) !important;
    border-radius: 10px !important;
    padding: 4px 8px !important; 
    cursor: pointer !important;
    display: flex !important;
    align-items: center;
    justify-content: center;
}

.mes_edit_buttons .menu_button i, 
.mes_edit_buttons .menu_button svg {
    color: #ffffff !important;
    font-size: 1.1em !important;
    text-shadow: 0 0 8px rgba(255, 183, 213, 0.9) !important;
}

.mes_edit_save i { color: var(--地雷系粉色) !important; }
.fa-trash-can, .fa-trash { color: var(--地雷系粉色) !important; }



/* 信息栏 (楼层/字符数/计时器) */
.mes .mes_timer, .mes .mesIDDisplay, .mes .tokenCounterDisplay {
    position: absolute !important; 
    color: #c8b1c8 !important; 
    font-size: calc(var(--mainFontSize) * 0.85); font-weight: 600; z-index: 5 !important;
    text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.6) !important;
}
.mes .mesIDDisplay { top: var(--楼层-上下位置) !important; left: var(--楼层-左右位置) !important; }
.mes .tokenCounterDisplay { top: var(--字符-上下位置) !important; left: var(--字符-左右位置) !important; }
.mes .mes_timer { top: var(--计时-上下位置) !important; left: var(--计时-左右位置) !important; }


/* 12. 消息内文本样式 - 地雷深梅子版 */
:root {
    /* 🍓 核心调色板：深梅子与哑光暗粉 */
    --jirai-plum-dark: #401728;     /* 你要求的深梅子紫 */
    --jirai-plum-deep: #1a1115;     /* 接近黑色的深紫 */
    --jirai-dusty-pink: #8b5d6d;    /* 暗粉色 */
    --jirai-text-bright: #f2ebee;   /* 极浅粉白，用于深色底上的文字 */
}

/* --- 斜体 (em)：黑色病娇波浪线 --- */
.mes_text em {
    font-style: italic !important;
    color: var(--jirai-dusty-pink) !important;
    text-decoration: underline 2px wavy var(--jirai-plum-deep) !important;
    text-underline-offset: 4px;
}

/* --- 🍓 引用 (q)：深色内嵌感胶带 --- */
.mes_text q {
    display: inline !important;
    background: rgba(64, 23, 40, 0.4) !important; /* 深梅子色半透明 */
    color: var(--jirai-text-bright) !important;
    font-style: normal !important;
    padding: 1px 6px !important;
    margin: 0 2px !important;
    border-radius: 3px !important;
    border: 1px solid var(--jirai-plum-dark) !important;    
    -webkit-box-decoration-break: clone;
    box-decoration-break: clone;
}
/* 🍓 自定义符号 */
.mes_text q::after {
    content: ' ♰' !important;
    color: var(--jirai-plum-dark) !important;
    font-size: 1.1em !important;
    font-weight: 900 !important;
    filter: drop-shadow(1px 1px 1px rgba(0,0,0,0.5));
}
.mes_text q::before { content: none !important; }

/* --- 加粗 --- */
.mes_text strong {
    display: inline !important;
    font-weight: 600 !important;
    color: var(--jirai-text-bright) !important;    
    -webkit-box-decoration-break: clone;
    box-decoration-break: clone;    
    background: var(--jirai-plum-dark) !important;
    padding: 1px 6px !important;
    margin: 0 3px !important;
    border-radius: 2px !important;
    text-shadow: 1px 1px 2px var(--jirai-plum-deep) !important;
    border-bottom: 2px solid var(--jirai-plum-deep) !important;
}

/* --- 代码块 --- */
.mes_text code {
    font-family: inherit !important;
    background: var(--jirai-plum-deep) !important;
    color: var(--jirai-dusty-pink) !important;
    padding: 1px 4px !important;
    border: 1px solid var(--jirai-plum-dark) !important;
    border-radius: 4px !important;
}

/* --- 引用块 (blockquote)：暗黑蕾丝边 --- */
.mes_text blockquote, .mes_reasoning blockquote {
    margin: 10px 0 !important;
    padding: 8px 15px !important;
    background: rgba(26, 17, 21, 0.85) !important;
    border-left: 4px solid var(--jirai-plum-dark) !important;
    color: #a69199 !important;
    font-size: 0.9em !important;
    box-shadow: inset 5px 0 15px rgba(0,0,0,0.4) !important;
}
/* --- 🍓 正文段落间距与颜色修正 --- */
.mes_text, .mes_reasoning {
    /* 🍓 核心修正：换成你要求的 #240214，并在暗色气泡下增加极细的浅色描边保证清晰度 */
    color: #240214 !important; 
    text-shadow: 0.2px 0.2px 0px rgba(255, 183, 213, 0.3) !important; 
}

.mes_text p + p, .mes_reasoning p + p {
    margin-top: 10px !important;
}

/* 13. 输入框区域 */
#send_form {
    display: flex !important; flex-direction: column;
    width: 96% !important; max-width: 420px !important;
    margin: 0px auto !important; position: relative; z-index: 10;
    padding: 5px 12px !important; transition: .3s;
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") center/cover !important;
    border-radius: 30px !important;
